module serial2parallel (
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0]dout_parallel,
    output reg dout_valid
);

reg [3:0] cnt;
reg [7:0] shift_reg;

always @(posedge clk) begin
    if (!rst_n) begin
        cnt <= 4'b0000;
        shift_reg <= 8'b0;
        dout_parallel <= 8'b0;
        dout_valid <= 1'b0;
    end else begin
        if (din_valid) begin
            shift_reg <= {shift_reg[6:0], din_serial};
            cnt <= cnt + 4'b0001;
            if (cnt == 4'b1000) begin
                dout_parallel <= shift_reg;
                dout_valid <= 1'b1;
            end else begin
                dout_valid <= 1'b0;
            end
        end else begin
            dout_valid <= 1'b0;
        end
    end
end

endmodule

module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output reg [15:0] result
);

    reg [7:0] dividend_reg, divisor_reg;
    reg [15:0] SR;
    reg [3:0] cnt;
    reg start_cnt;
    reg [7:0] NEG_DIVISOR;

    always @(posedge clk) begin
        if (rst) begin
            res_valid <= 0;
            cnt <= 0;
            start_cnt <= 0;
        end
        else if (opn_valid && !res_valid) begin
            dividend_reg <= dividend;
            divisor_reg <= divisor;
            SR <= {1'b0, dividend_reg};
            NEG_DIVISOR <= (sign && divisor_reg[7]) ? ~divisor_reg + 1 : divisor_reg;
            cnt <= 1;
            start_cnt <= 1;
        end
        else if (start_cnt) begin
            if (cnt == 8) begin
                cnt <= 0;
                start_cnt <= 0;
                result <= SR;
            end
            else begin
                cnt <= cnt + 1;
                {SR, NEG_DIVISOR} <= {SR[14:0], NEG_DIVISOR};
            end
        end
        else if (res_valid && res_ready) begin
            res_valid <= 0;
        end
        else begin
            res_valid <= res_valid;
        end
    end

endmodule

module width_8to16 (
    input 				   clk,
    input 				   rst_n,
    input				      valid_in,
    input	   [7:0]		   data_in,
    output	reg			valid_out,
    output   reg [15:0]	data_out
);

reg [7:0] data_lock;
reg flag;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data_out <= 16'b0;
        valid_out <= 1'b0;
        data_lock <= 8'b0;
        flag <= 1'b0;
    end else begin
        if (valid_in && flag) begin
            data_out <= {data_lock, data_in};
            valid_out <= 1'b1;
            flag <= 1'b0;
        end else if (valid_in && !flag) begin
            data_lock <= data_in;
            flag <= 1'b1;
            valid_out <= 1'b0;
        end else begin
            valid_out <= 1'b0;
        end
    end
end
endmodule

module traffic_light #(
    parameter idle = 2'd0,
    parameter s1_red = 2'd1,
    parameter s2_yellow = 2'd2,
    parameter s3_green = 2'd3
) (
    input rst_n,
    input clk,
    input pass_request,
    output wire[7:0]clock,
    output reg red,
    output reg yellow,
    output reg green
);

    reg [7:0] cnt;
    reg [1:0] state;
    reg p_red, p_yellow, p_green;


    always@(posedge clk,negedge rst_n)begin
        if(!rst_n)begin
            state <= idle;
            p_red <= 1'b0;
            p_yellow <= 1'b0;
            p_green <= 1'b0;
        end
        else begin
            case(state)
                idle:begin
                    p_red <= 1'b0;
                    p_yellow <= 1'b0;
                    p_green <= 1'b0;
                    state <= s1_red;
                end
                s1_red:begin
                    p_red <= 1'b1;
                    p_yellow <= 1'b0;
                    p_green <= 1'b0;
                    if(cnt==3)begin
                        state <= s3_green;
                    end
                    else begin
                        state <= s1_red;
                    end
                end
                s2_yellow:begin
                    p_red <= 1'b0;
                    p_yellow <= 1'b1;
                    p_green <= 1'b0;
                    if(cnt==3)begin
                        state <= s1_red;
                    end
                    else begin
                        state <= s2_yellow;
                    end
                end
                s3_green:begin
                    p_red <= 1'b0;
                    p_yellow <= 1'b0;
                    p_green <= 1'b1;
                    if(cnt==3)begin
                        state <= s2_yellow;
                    end
                    else begin
                        state <= s3_green;
                    end
                end
            endcase
        end
    end

    always@(posedge clk,negedge rst_n)begin
        if(!rst_n)begin
            cnt <= 8'd10;
        end
        else begin
            if(pass_request&&green&&(cnt>10))begin
                cnt <= 8'd10;
            end
            else if(!green&&p_green)begin
                cnt <= 8'd60;
            end
            else if(!yellow&&p_yellow)begin
                cnt <= 8'd5;
            end
            else if(!red&&p_red)begin
                cnt <= 8'd10;
            end
            else begin
                cnt <= cnt - 8'd1;
            end
        end
    end

    assign clock = cnt;

    always@(posedge clk,negedge rst_n)begin
        if(!rst_n)begin
            red <= 1'b0;
            yellow <= 1'b0;
            green <= 1'b0;
        end
        else begin
            red <= p_red;
            yellow <= p_yellow;
            green <= p_green;
        end
    end
endmodule

module multi_16bit (
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);
    reg [4:0] i;
    reg done_r;
    reg [15:0] areg, breg;
    reg [31:0] yout_r;
    assign done = done_r;
    assign yout = yout_r;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            i <= 5'd0;
        end
        else if(start && i < 5'd17) begin
            i <= i + 1;
        end
        else if(!start) begin
            i <= 5'd0;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            done_r <= 1'b0;
        end
        else if(i == 5'd16) begin
            done_r <= 1'b1;
        end
        else if(i == 5'd17) begin
            done_r <= 1'b0;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            areg <= 16'd0;
            breg <= 16'd0;
            yout_r <= 32'd0;
        end
        else if(start) begin
            if(i == 5'd0) begin
                areg <= ain;
                breg <= bin;
            end
            else if(i > 5'd0 && i < 5'd17) begin
                if(areg[i-1]) begin
                    yout_r <= yout_r + (breg << (i-1));
                end
            end
        end
    end
endmodule

module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);
    reg [size-1:0] mul_a_reg;
    reg [size-1:0] mul_b_reg;
    reg [2*size-1:0] mul_out_reg;
    reg [2:0] mul_en_out_reg;
    wire [size-1:0] partial_products [size-1:0];
    wire [2*size-1:0] sum [3:0];

    always @(posedge clk) begin
        if (!rst_n) begin
            mul_a_reg <= 0;
            mul_b_reg <= 0;
        end else if (mul_en_in) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
        end
    end

    genvar i, j;
    generate
        for (i = 0; i < size; i = i + 1) begin
            for (j = 0; j < size; j = j + 1) begin
                assign partial_products[i][j] = mul_a_reg[i] & mul_b_reg[j];
            end
        end
    endgenerate

    always @(posedge clk) begin
        if (!rst_n) begin
            mul_out_reg <= 0;
        end else begin
            mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3];
        end
    end

    always @(posedge clk) begin
        if (!rst_n) begin
            mul_en_out_reg <= 0;
            mul_out <= 0;
        end else begin
            mul_en_out_reg <= {mul_en_out_reg[1:0], mul_en_in};
            mul_out <= (mul_en_out_reg[2]) ? mul_out_reg : 0;
        end
    end

    assign sum[0] = {partial_products[0][size-1], partial_products[1][size-1], partial_products[2][size-1], partial_products[3][size-1]};
    assign sum[1] = {partial_products[4][size-1], partial_products[5][size-1], partial_products[6][size-1], partial_products[7][size-1]};
    assign sum[2] = {partial_products[8][size-1], partial_products[9][size-1], partial_products[10][size-1], partial_products[11][size-1]};
    assign sum[3] = {partial_products[12][size-1], partial_products[13][size-1], partial_products[14][size-1], partial_products[15][size-1]};

endmodule

module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output reg valid_out,
    output reg dout
);

    reg [1:0] cnt;
    reg [3:0] data;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 2'b00;
            data <= 4'b0000;
            valid_out <= 1'b0;
        end else begin
            if (cnt == 2'b11) begin
                cnt <= 2'b00;
                data <= d;
                valid_out <= 1'b1;
            end else begin
                cnt <= cnt + 1;
                data <= {data[2:0], data[3]};
                valid_out <= 1'b0;
            end
        end
    end

    assign dout = data[3];

endmodule

module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);

always @(*) begin
    if (B == 0) begin
        result = 0;
        odd = A;
    end else begin
        result = A / B;
        odd = A % B;
    end
end

endmodule

module multi_8bit (
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] product_reg;
    reg [7:0] multiplicand;
    reg [7:0] multiplier;
    integer i;

    always @(*) begin
        multiplicand = A;
        multiplier = B;
        product_reg = 16'd0;

        for (i = 0; i < 8; i = i + 1) begin
            if (multiplier[i]) begin
                product_reg = product_reg + (multiplicand << i);
            end
        end

        product = product_reg;
    end

endmodule

module freq_div (
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input RST
);

    reg [0:0] cnt_50;
    reg [3:0] cnt_10;
    reg [6:0] cnt_100;

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            cnt_50 <= 1'b0;
        end else begin
            cnt_50 <= ~cnt_50;
        end
    end

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            cnt_10 <= 4'd0;
        end else if (cnt_10 == 4'd9) begin
            cnt_10 <= 4'd0;
        end else begin
            cnt_10 <= cnt_10 + 1;
        end
    end

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            cnt_100 <= 7'd0;
        end else if (cnt_100 == 7'd99) begin
            cnt_100 <= 7'd0;
        end else begin
            cnt_100 <= cnt_100 + 1;
        end
    end

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_50 <= 1'b0;
        end else begin
            CLK_50 <= ~CLK_50;
        end
    end

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_10 <= 1'b0;
        end else if (cnt_10 == 4'd9) begin
            CLK_10 <= ~CLK_10;
        end
    end

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            CLK_1 <= 1'b0;
        end else if (cnt_100 == 7'd99) begin
            CLK_1 <= ~CLK_1;
        end
    end

endmodule

module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output reg [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output flag
);

    reg [31:0] res;
    wire signed [31:0] a_signed;
    wire signed [31:0] b_signed;

    assign a_signed = a;
    assign b_signed = b;
    assign flag = (aluc == SLT || aluc == SLTU) ? ((aluc == SLT) ? ($signed(a) < $signed(b)) : (a < b)) : 1'b0;

    always @(*) begin
        case (aluc)
            ADD:  {overflow, res} = a_signed + b_signed;
            ADDU: {overflow, res} = a + b;
            SUB:  {overflow, res} = a_signed - b_signed;
            SUBU: {overflow, res} = a - b;
            AND:  res = a & b;
            OR:   res = a | b;
            XOR:  res = a ^ b;
            NOR:  res = ~(a | b);
            SLT:  res = (a_signed < b_signed);
            SLTU: res = (a < b);
            SLL:  res = b << a[4:0];
            SRL:  res = b >> a[4:0];
            SRA:  res = b_signed >>> a[4:0];
            SLLV: res = b << a[4:0];
            SRLV: res = b >> a[4:0];
            SRAV: res = b_signed >>> a[4:0];
            LUI:  res = {a[15:0], 16'b0};
            default: res = 32'b0;
        endcase

        carry <= (aluc == ADD || aluc == ADDU) ? res[32] :
                 (aluc == SUB || aluc == SUBU) ? res[32] : 1'b0;
    end

    assign negative = res[31];
    assign r = res;

endmodule

module edge_detect (
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin

        rise <= 1'b0;
        down <= 1'b0;
    end else begin

        if (a && !prev_a) begin

            rise <= 1'b1;
            down <= 1'b0;
        end else if (!a && prev_a) begin

            rise <= 1'b0;
            down <= 1'b1;
        end else begin

            rise <= 1'b0;
            down <= 1'b0;
        end
    end
end

reg prev_a;

always @(posedge clk) begin

    prev_a <= a;
end
endmodule

module adder_16bit (
    input [15:0] a,
    input [15:0] b,
    input Cin,
    output [15:0] y,
    output Co
);

wire [7:0] sum1, sum2;
wire c1, c2;

assign {c1, sum1} = a[7:0] + b[7:0] + Cin;
assign {c2, sum2} = a[15:8] + b[15:8] + c1;

assign y = {sum2, sum1};

assign Co = c2;
endmodule

module add8 (
    input [7:0] a,
    input [7:0] b,
    input Cin,
    output [7:0] y,
    output Co
);

    wire Co_temp;

    add4 add4_inst1 (
        .a(a[7:4]),
        .b(b[7:4]),
        .Cin(Co_temp),
        .y(y[7:4]),
        .Co(Co)
    );

    add4 add4_inst2 (
        .a(a[3:0]),
        .b(b[3:0]),
        .Cin(Cin),
        .y(y[3:0]),
        .Co(Co_temp)
    );

endmodule

module add4 (
    input [3:0] a,
    input [3:0] b,
    input Cin,
    output [3:0] y,
    output Co
);

    wire Co_temp;

    add2 add2_inst1 (
        .a(a[3:2]),
        .b(b[3:2]),
        .Cin(Co_temp),
        .y(y[3:2]),
        .Co(Co)
    );

    add2 add2_inst2 (
        .a(a[1:0]),
        .b(b[1:0]),
        .Cin(Cin),
        .y(y[1:0]),
