    ); 

endmodule

module add2 (
    input [1:0] a,
    input [1:0] b,
    input Cin,
    output [1:0] y,
    output Co
);

    wire Co_temp;

    add1 add1_inst1 (
        .a(a[1]),
        .b(b[1]),
        .Cin(Co_temp),
        .y(y[1]),
        .Co(Co)
    );

    add1 add1_inst2 (
        .a(a[0]),
        .b(b[0]),
        .Cin(Cin),
        .y(y[0]),
        .Co(Co_temp)
    );

endmodule

module add1 (
    input a,
    input b,
    input Cin,
    output y,
    output Co
);
    assign y = ((~a) & (~b) & Cin | (~a) & b & (~Cin) | a & (~b) & (~Cin) | (a & b & Cin));
    assign Co = ((~a & b & Cin) | (a & ~b & Cin) | (a & b & ~Cin) | (a & b & Cin));

endmodule

module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);
    reg [7:0] sum_tmp1, sum_tmp2;

    integer i,j;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum_tmp1 <= 8'b0;
            sum_tmp2 <= 8'b0;
            mul_out <= 8'b0;
        end 
        else begin
            sum_tmp1 <= ({4'b0,mul_b[0]}?mul_a:{4'b0,4'b0})+(({4'b0,mul_b[1]}?mul_a<<1:{4'b0,4'b0}));
            sum_tmp2 <= ({4'b0,mul_b[2]}?mul_a<<2:{4'b0,4'b0})+(({4'b0,mul_b[3]}?mul_a<<3:{4'b0,4'b0}));
            mul_out <= sum_tmp1+sum_tmp2;
        end
    end

endmodule

module calendar (
    input CLK,
    input RST,
    output reg [5:0] Hours,
    output reg [5:0] Mins,
    output reg [5:0] Secs
);

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        Secs <= 6'b000000;
    end else if (Secs == 6'b111011) begin
        Secs <= 6'b000000;
    end else begin
        Secs <= Secs + 1;
    end
end

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        Mins <= 6'b000000;
    end else if ((Mins == 6'b111011) && (Secs == 6'b111011)) begin
        Mins <= 6'b000000;
    end else if (Secs == 6'b111011) begin
        Mins <= Mins + 1;
    end else begin
        Mins <= Mins;
    end
end

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        Hours <= 6'b000000;
    end else if ((Hours == 6'b010111) && (Mins == 6'b111011) && (Secs == 6'b111011)) begin
        Hours <= 6'b000000;
    end else if ((Mins == 6'b111011) && (Secs == 6'b111011)) begin
        Hours <= Hours + 1;
    end else begin
        Hours <= Hours;
    end
end
endmodule

module counter_12 (
    input rst_n,
    input clk,
    input valid_count,
    output reg [3:0] out
);
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            out <= 4'b0000;
        else if (valid_count) begin
            if (out == 4'd11) out <= 4'b0000; else out <= out + 1;
        end
    end
endmodule

module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output wire				wfull,
    output wire				rempty,
    output reg [WIDTH-1:0]	rdata
);

    reg [ADDR_WIDTH:0] wptr, rptr;
    reg [ADDR_WIDTH:0] wptr_rclk, rptr_wclk;
    reg [WIDTH-1:0] ram[DEPTH-1:0];
    integer i;

    always @(posedge wclk) begin
        if (!wrstn)
            wptr <= 0;
        else if (winc && !wfull)
            wptr <= wptr + 1;
    end

    always @(posedge rclk) begin
        if (!rrstn)
            rptr <= 0;
        else if (rinc && !rempty)
            rptr <= rptr + 1;
    end

    always @(wptr) begin
        wptr_rclk <= wptr;
    end

    always @(rptr) begin
        rptr_wclk <= rptr;
    end

    assign wfull = (wptr_rclk[ADDR_WIDTH-1:0] == rptr_wclk[ADDR_WIDTH-1:0]) && (wptr_rclk[ADDR_WIDTH] != rptr_wclk[ADDR_WIDTH]);
    assign rempty = (wptr == rptr);

    always @(posedge wclk) begin
        if (winc && !wfull)
            ram[wptr[ADDR_WIDTH-1:0]] <= wdata;
    end

    always @(posedge rclk) begin
        if (rinc && !rempty)
            rdata <= ram[rptr[ADDR_WIDTH-1:0]];
    end

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule

module adder_32bit (
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

